+.setup__codeRow code {
   flex: 1;
+  min-width: 0;
+}
+
+.setup__copy {
+  width: 36px;
+  height: 36px;
+  padding: 0;
+  display: grid;
+  place-items: center;
+}
+
+.setup__copy svg {
+  width: 16px;
+  height: 16px;
+  fill: currentColor;
+}
+
+.setup__hint {
